export default {
  wrapper: "flex items-center -space-x-px",
  base: "",
  rounded: "first:rounded-s-md last:rounded-e-md",
  default: {
    size: "sm",
    activeButton: {
      color: "primary"
    },
    inactiveButton: {
      color: "white"
    },
    firstButton: {
      color: "white",
      class: "rtl:[&_span:first-child]:rotate-180",
      icon: "i-heroicons-chevron-double-left-20-solid"
    },
    lastButton: {
      color: "white",
      class: "rtl:[&_span:last-child]:rotate-180",
      icon: "i-heroicons-chevron-double-right-20-solid"
    },
    prevButton: {
      color: "white",
      class: "rtl:[&_span:first-child]:rotate-180",
      icon: "i-heroicons-chevron-left-20-solid"
    },
    nextButton: {
      color: "white",
      class: "rtl:[&_span:last-child]:rotate-180",
      icon: "i-heroicons-chevron-right-20-solid"
    }
  }
};
<template>
  <div :class="ui.wrapper" v-bind="attrs">
    <slot name="first" :on-click="onClickFirst" :can-go-first="canGoFirstOrPrev">
      <UButton
        v-if="firstButton && showFirst"
        :size="size"
        :to="to?.(1)"
        :disabled="!canGoFirstOrPrev || disabled"
        :class="[ui.base, ui.rounded]"
        v-bind="{ ...ui.default.firstButton || {}, ...firstButton }"
        :ui="{ rounded: '' }"
        aria-label="First"
        @click="onClickFirst"
      />
    </slot>

    <slot name="prev" :on-click="onClickPrev" :can-go-prev="canGoFirstOrPrev">
      <UButton
        v-if="prevButton"
        :size="size"
        :to="to?.(currentPage - 1)"
        :disabled="!canGoFirstOrPrev || disabled"
        :class="[ui.base, ui.rounded]"
        v-bind="{ ...ui.default.prevButton || {}, ...prevButton }"
        :ui="{ rounded: '' }"
        aria-label="Prev"
        @click="onClickPrev"
      />
    </slot>

    <UButton
      v-for="(page, index) of displayedPages"
      :key="`${page}-${index}`"
      :to="typeof page === 'number' ? to?.(page) : null"
      :size="size"
      :disabled="disabled"
      :label="`${page}`"
      v-bind="page === currentPage ? { ...ui.default.activeButton || {}, ...activeButton } : { ...ui.default.inactiveButton || {}, ...inactiveButton }"
      :class="[{ 'pointer-events-none': typeof page === 'string', 'z-[1]': page === currentPage }, ui.base, ui.rounded]"
      :ui="{ rounded: '' }"
      @click="() => onClickPage(page)"
    />

    <slot name="next" :on-click="onClickNext" :can-go-next="canGoLastOrNext">
      <UButton
        v-if="nextButton"
        :size="size"
        :to="to?.(currentPage + 1)"
        :disabled="!canGoLastOrNext || disabled"
        :class="[ui.base, ui.rounded]"
        v-bind="{ ...ui.default.nextButton || {}, ...nextButton }"
        :ui="{ rounded: '' }"
        aria-label="Next"
        @click="onClickNext"
      />
    </slot>

    <slot name="last" :on-click="onClickLast" :can-go-last="canGoLastOrNext">
      <UButton
        v-if="lastButton && showLast"
        :size="size"
        :to="to?.(pages.length)"
        :disabled="!canGoLastOrNext || disabled"
        :class="[ui.base, ui.rounded]"
        v-bind="{ ...ui.default.lastButton || {}, ...lastButton }"
        :ui="{ rounded: '' }"
        aria-label="Last"
        @click="onClickLast"
      />
    </slot>
  </div>
</template>

<script>
import { computed, toRef, defineComponent } from "vue";
import UButton from "../elements/Button.vue";
import { useUI } from "../../composables/useUI";
import { mergeConfig } from "../../utils";
import appConfig from "#build/app.config";
import { pagination, button } from "#ui/ui.config";
const config = mergeConfig(appConfig.ui.strategy, appConfig.ui.pagination, pagination);
const buttonConfig = mergeConfig(appConfig.ui.strategy, appConfig.ui.button, button);
export default defineComponent({
  components: {
    UButton
  },
  inheritAttrs: false,
  props: {
    modelValue: {
      type: Number,
      required: true
    },
    pageCount: {
      type: Number,
      default: 10
    },
    total: {
      type: Number,
      required: true
    },
    max: {
      type: Number,
      default: 7,
      validate(value) {
        return value >= 5 && value < Number.MAX_VALUE;
      }
    },
    disabled: {
      type: Boolean,
      default: false
    },
    size: {
      type: String,
      default: () => config.default.size,
      validator(value) {
        return Object.keys(buttonConfig.size).includes(value);
      }
    },
    to: {
      type: Function,
      default: null
    },
    activeButton: {
      type: Object,
      default: () => config.default.activeButton
    },
    inactiveButton: {
      type: Object,
      default: () => config.default.inactiveButton
    },
    showFirst: {
      type: Boolean,
      default: false
    },
    showLast: {
      type: Boolean,
      default: false
    },
    firstButton: {
      type: Object,
      default: () => config.default.firstButton
    },
    lastButton: {
      type: Object,
      default: () => config.default.lastButton
    },
    prevButton: {
      type: Object,
      default: () => config.default.prevButton
    },
    nextButton: {
      type: Object,
      default: () => config.default.nextButton
    },
    divider: {
      type: String,
      default: "\u2026"
    },
    class: {
      type: [String, Object, Array],
      default: () => ""
    },
    ui: {
      type: Object,
      default: () => ({})
    }
  },
  emits: ["update:modelValue"],
  setup(props, { emit }) {
    const { ui, attrs } = useUI("pagination", toRef(props, "ui"), config, toRef(props, "class"));
    const currentPage = computed({
      get() {
        return props.modelValue;
      },
      set(value) {
        emit("update:modelValue", value);
      }
    });
    const pages = computed(() => Array.from({ length: Math.ceil(props.total / props.pageCount) }, (_, i) => i + 1));
    const displayedPages = computed(() => {
      const totalPages = pages.value.length;
      const current = currentPage.value;
      const maxDisplayedPages = Math.max(props.max, 5);
      const r = Math.floor((Math.min(maxDisplayedPages, totalPages) - 5) / 2);
      const r1 = current - r;
      const r2 = current + r;
      const beforeWrapped = r1 - 1 > 1;
      const afterWrapped = r2 + 1 < totalPages;
      const items = [];
      if (totalPages <= maxDisplayedPages) {
        for (let i = 1; i <= totalPages; i++) {
          items.push(i);
        }
        return items;
      }
      items.push(1);
      if (beforeWrapped) items.push(props.divider);
      if (!afterWrapped) {
        const addedItems = current + r + 2 - totalPages;
        for (let i = current - r - addedItems; i <= current - r - 1; i++) {
          items.push(i);
        }
      }
      for (let i = Math.max(2, r1); i <= Math.min(totalPages, r2); i++) {
        items.push(i);
      }
      if (!beforeWrapped) {
        const addedItems = 1 - (current - r - 2);
        for (let i = current + r + 1; i <= current + r + addedItems; i++) {
          items.push(i);
        }
      }
      if (afterWrapped) items.push(props.divider);
      if (r2 < totalPages) {
        items.push(totalPages);
      }
      if (items.length >= 3 && items[1] === props.divider && items[2] === 3) {
        items[1] = 2;
      }
      if (items.length >= 3 && items[items.length - 2] === props.divider && items[items.length - 1] === items.length) {
        items[items.length - 2] = items.length - 1;
      }
      return items;
    });
    const canGoFirstOrPrev = computed(() => currentPage.value > 1);
    const canGoLastOrNext = computed(() => currentPage.value < pages.value.length);
    function onClickFirst() {
      if (!canGoFirstOrPrev.value) {
        return;
      }
      currentPage.value = 1;
    }
    function onClickLast() {
      if (!canGoLastOrNext.value) {
        return;
      }
      currentPage.value = pages.value.length;
    }
    function onClickPage(page) {
      if (typeof page === "string") {
        return;
      }
      currentPage.value = page;
    }
    function onClickPrev() {
      if (!canGoFirstOrPrev.value) {
        return;
      }
      currentPage.value--;
    }
    function onClickNext() {
      if (!canGoLastOrNext.value) {
        return;
      }
      currentPage.value++;
    }
    return {
      // eslint-disable-next-line vue/no-dupe-keys
      ui,
      attrs,
      currentPage,
      pages,
      displayedPages,
      canGoLastOrNext,
      canGoFirstOrPrev,
      onClickPrev,
      onClickNext,
      onClickPage,
      onClickFirst,
      onClickLast
    };
  }
});
</script>
<template>
  <div>
    <!-- Header -->
    <div class="mb-6 flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
      <div>
        <h1 class="text-2xl font-bold text-gray-900">Commandes</h1>
        <p class="text-gray-500 mt-1">Gérez toutes les commandes</p>
      </div>
      <div class="flex items-center gap-3">
        <UInput
          v-model="search"
          placeholder="Rechercher..."
          icon="i-lucide-search"
          class="w-64"
        />
        <UButton @click="fetchOrders" color="gray" variant="outline" icon="i-lucide-refresh-cw">
          Actualiser
        </UButton>
      </div>
    </div>

    <!-- Filters -->
    <div class="bg-white rounded-xl shadow-sm border border-gray-100 p-4 mb-6">
      <div class="flex flex-wrap items-center gap-4">
        <USelectMenu
          v-model="statusFilter"
          :options="statusOptions"
          placeholder="Statut"
          class="w-40"
        />
        <USelectMenu
          v-model="fulfillmentFilter"
          :options="fulfillmentOptions"
          placeholder="Livraison"
          class="w-40"
        />
        <UButton v-if="hasActiveFilters" @click="clearFilters" color="gray" variant="ghost" size="sm">
          Effacer les filtres
        </UButton>
      </div>
    </div>

    <!-- Orders Table -->
    <div class="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
      <UTable
        :columns="columns"
        :rows="filteredOrders"
        :loading="loading"
        :empty-state="{ icon: 'i-lucide-package', label: 'Aucune commande trouvée' }"
      >
        <!-- ID Column -->
        <template #display_id-data="{ row }">
          <NuxtLink :to="`/admin/commandes/${row.id}`" class="font-medium text-primary-600 hover:text-primary-700">
            #{{ row.display_id || row.id.slice(0, 8).toUpperCase() }}
          </NuxtLink>
        </template>

        <!-- Customer Column -->
        <template #customer-data="{ row }">
          <div>
            <p class="font-medium text-gray-900">{{ row.customer_first_name }} {{ row.customer_last_name }}</p>
            <p class="text-xs text-gray-500">{{ row.email }}</p>
          </div>
        </template>

        <!-- Recipient Column -->
        <template #recipient-data="{ row }">
          <div>
            <p class="font-medium text-gray-900">{{ row.recipient_name || '-' }}</p>
            <p class="text-xs text-gray-500">{{ row.recipient_phone || '-' }}</p>
          </div>
        </template>

        <!-- Status Column -->
        <template #status-data="{ row }">
          <UBadge :color="getStatusColor(row.status)" variant="soft" size="sm">
            {{ getStatusLabel(row.status) }}
          </UBadge>
        </template>

        <!-- Fulfillment Column -->
        <template #fulfillment-data="{ row }">
          <UBadge :color="getFulfillmentColor(row.fulfillment_status)" variant="soft" size="sm">
            {{ getFulfillmentLabel(row.fulfillment_status) }}
          </UBadge>
        </template>

        <!-- Total Column -->
        <template #total-data="{ row }">
          <span class="font-semibold text-gray-900">{{ formatPrice(row.total) }}</span>
        </template>

        <!-- Date Column -->
        <template #date-data="{ row }">
          <span class="text-sm text-gray-500">{{ formatDate(row.created_at) }}</span>
        </template>

        <!-- Assigned Column -->
        <template #assigned-data="{ row }">
          <div v-if="row.assigned_to" class="flex items-center gap-2">
            <div class="w-6 h-6 rounded-full bg-green-100 flex items-center justify-center">
              <Icon name="lucide:user" class="w-3 h-3 text-green-600" />
            </div>
            <span class="text-sm text-gray-700">Assigné</span>
          </div>
          <span v-else class="text-sm text-gray-400">-</span>
        </template>

        <!-- Actions Column -->
        <template #actions-data="{ row }">
          <UDropdown :items="getRowActions(row)" :popper="{ placement: 'bottom-end' }">
            <UButton color="gray" variant="ghost" icon="i-lucide-more-vertical" size="sm" />
          </UDropdown>
        </template>
      </UTable>

      <!-- Pagination -->
      <div v-if="totalPages > 1" class="border-t border-gray-100 px-4 py-3 flex items-center justify-between">
        <p class="text-sm text-gray-500">
          {{ filteredOrders.length }} commande(s) sur {{ orders.length }}
        </p>
        <UPagination v-model="currentPage" :total="totalPages" :page-count="pageSize" />
      </div>
    </div>

    <!-- Assign Livreur Modal -->
    <UModal v-model="showAssignModal">
      <div class="p-6">
        <h3 class="text-lg font-semibold text-gray-900 mb-4">Assigner un livreur</h3>
        <p class="text-sm text-gray-500 mb-4">
          Commande #{{ selectedOrder?.display_id || selectedOrder?.id?.slice(0, 8).toUpperCase() }}
        </p>

        <USelectMenu
          v-model="selectedLivreur"
          :options="livreurs"
          option-attribute="label"
          value-attribute="value"
          placeholder="Sélectionner un livreur"
          class="mb-4"
        />

        <div class="flex justify-end gap-3">
          <UButton color="gray" variant="outline" @click="showAssignModal = false">
            Annuler
          </UButton>
          <UButton color="primary" :loading="assigning" @click="assignLivreur">
            Assigner
          </UButton>
        </div>
      </div>
    </UModal>
  </div>
</template>

<script setup lang="ts">
definePageMeta({
  layout: 'admin',
  middleware: ['admin']
})

const api = useBackendApi()
const toast = useToast()

// State
const loading = ref(true)
const orders = ref<any[]>([])
const search = ref('')
const statusFilter = ref<string | null>(null)
const fulfillmentFilter = ref<string | null>(null)
const currentPage = ref(1)
const pageSize = 20

// Assign modal
const showAssignModal = ref(false)
const selectedOrder = ref<any | null>(null)
const selectedLivreur = ref<string | null>(null)
const livreurs = ref<{ label: string; value: string }[]>([])
const assigning = ref(false)

// Columns
const columns = [
  { key: 'display_id', label: 'ID' },
  { key: 'customer', label: 'Client' },
  { key: 'recipient', label: 'Destinataire' },
  { key: 'status', label: 'Statut' },
  { key: 'fulfillment', label: 'Livraison' },
  { key: 'total', label: 'Total' },
  { key: 'date', label: 'Date' },
  { key: 'assigned', label: 'Livreur' },
  { key: 'actions', label: '' }
]

// Filter options
const statusOptions = [
  { label: 'Tous', value: null },
  { label: 'En attente', value: 'pending' },
  { label: 'En cours', value: 'processing' },
  { label: 'Terminé', value: 'completed' },
  { label: 'Annulé', value: 'cancelled' }
]

const fulfillmentOptions = [
  { label: 'Tous', value: null },
  { label: 'Non traité', value: 'not_fulfilled' },
  { label: 'Prêt', value: 'fulfilled' },
  { label: 'En livraison', value: 'shipped' },
  { label: 'Livré', value: 'delivered' }
]

// Computed
const hasActiveFilters = computed(() => {
  return statusFilter.value || fulfillmentFilter.value || search.value
})

const filteredOrders = computed(() => {
  let result = orders.value

  if (search.value) {
    const s = search.value.toLowerCase()
    result = result.filter(o => 
      (o.display_id || String(o.id))?.toLowerCase().includes(s) ||
      o.email?.toLowerCase().includes(s) ||
      o.customer_first_name?.toLowerCase().includes(s) ||
      o.customer_last_name?.toLowerCase().includes(s) ||
      o.recipient_name?.toLowerCase().includes(s)
    )
  }

  if (statusFilter.value) {
    result = result.filter(o => o.status === statusFilter.value)
  }

  if (fulfillmentFilter.value) {
    result = result.filter(o => o.fulfillment_status === fulfillmentFilter.value)
  }

  return result
})

const totalPages = computed(() => Math.ceil(filteredOrders.value.length / pageSize))

// Methods
const fetchOrders = async () => {
  loading.value = true
  try {
    const result = await api.adminOrders({ limit: 200 })
    orders.value = result?.data || []
  } catch (error) {
    console.error('Error fetching orders:', error)
    toast.add({ title: 'Erreur', description: 'Impossible de charger les commandes', color: 'red' })
  } finally {
    loading.value = false
  }
}

const fetchLivreurs = async () => {
  try {
    const result = await api.adminLivreurs()
    if (result?.data) {
      livreurs.value = result.data.map((l: any) => ({
        label: `${l.first_name} ${l.last_name}`,
        value: l.user_id
      }))
    }
  } catch (error) {
    console.error('Error fetching livreurs:', error)
  }
}

const openAssignModal = (order: any) => {
  selectedOrder.value = order
  selectedLivreur.value = order.assigned_to || null
  showAssignModal.value = true
}

const assignLivreur = async () => {
  if (!selectedOrder.value || !selectedLivreur.value) return

  assigning.value = true
  try {
    await api.adminOrderUpdate(selectedOrder.value.id, {
      assigned_to: selectedLivreur.value,
      fulfillment_status: 'fulfilled'
    })

    toast.add({ title: 'Succès', description: 'Livreur assigné avec succès', color: 'green' })
    showAssignModal.value = false
    fetchOrders()
  } catch (error) {
    console.error('Error assigning livreur:', error)
    toast.add({ title: 'Erreur', description: "Impossible d'assigner le livreur", color: 'red' })
  } finally {
    assigning.value = false
  }
}

const getRowActions = (row: any) => [
  [{
    label: 'Voir détails',
    icon: 'i-lucide-eye',
    click: () => navigateTo(`/admin/commandes/${row.id}`)
  }],
  [{
    label: 'Assigner livreur',
    icon: 'i-lucide-truck',
    click: () => openAssignModal(row)
  }]
]

const clearFilters = () => {
  search.value = ''
  statusFilter.value = null
  fulfillmentFilter.value = null
}

// Helpers
const formatPrice = (amount: number) => {
  return new Intl.NumberFormat('fr-FR', { style: 'currency', currency: 'EUR' }).format(amount || 0)
}

const formatDate = (date: string) => {
  return new Date(date).toLocaleDateString('fr-FR', { day: 'numeric', month: 'short', year: 'numeric' })
}

const getStatusColor = (status: string) => {
  const colors: Record<string, string> = {
    pending: 'amber',
    processing: 'blue',
    completed: 'green',
    cancelled: 'red'
  }
  return colors[status] || 'gray'
}

const getStatusLabel = (status: string) => {
  const labels: Record<string, string> = {
    pending: 'En attente',
    processing: 'En cours',
    completed: 'Terminé',
    cancelled: 'Annulé'
  }
  return labels[status] || status
}

const getFulfillmentColor = (status: string) => {
  const colors: Record<string, string> = {
    not_fulfilled: 'gray',
    fulfilled: 'cyan',
    shipped: 'indigo',
    delivered: 'green'
  }
  return colors[status] || 'gray'
}

const getFulfillmentLabel = (status: string) => {
  const labels: Record<string, string> = {
    not_fulfilled: 'Non traité',
    fulfilled: 'Prêt',
    shipped: 'En livraison',
    delivered: 'Livré'
  }
  return labels[status] || status
}

// Fetch on mount
onMounted(() => {
  fetchOrders()
  fetchLivreurs()
})

useHead({
  title: 'Commandes - Admin TchadBox'
})
</script>
